// Copyright (c) HashiCorp, Inc.// SPDX-License-Identifier: MPL-2.0package ecr_testimport (	"testing"	"github.com/aws/aws-sdk-go/service/ecr"	"github.com/hashicorp/terraform-plugin-testing/helper/resource"	"github.com/hashicorp/terraform-provider-aws/internal/acctest")func init() {	acctest.RegisterServiceErrorCheckFunc(ecr.EndpointsID, testAccErrorCheckSkip)}// testAccErrorCheckSkip skips tests that have error messages indicating unsupported featuresfunc testAccErrorCheckSkip(t *testing.T) resource.ErrorCheckFunc {	return acctest.ErrorCheckSkipMessagesContaining(t,		"This feature is disabled",	)}